import React, { useEffect, useState } from 'react';
import Column from '../Column';
import * as C from './style';

function Main({ dados }) {

    
    const [ pedidos, setPedidos ] = useState()
    
    setPedidos([])

    useEffect(() => {
        setPedidos(dados)
    }, [])

    var pedidos1 = pedidos.filter( e => e.hr === "19:30")
    var pedidos2 = pedidos.filter( e => e.hr === "20:00")
    var pedidos3 = pedidos.filter( e => e.hr === "20:30")
    var pedidos4 = pedidos.filter( e => e.hr === "21:00")
    var pedidos5 = pedidos.filter( e => e.hr === "21:30")

    return (
        <C.Container>
            <Column title='19:30' pedidos={pedidos1}/>
            <Column title='20:00' pedidos={pedidos2}/>
            <Column title='20:30' pedidos={pedidos3}/>
            <Column title='21:00' pedidos={pedidos4}/>
            <Column title='21:30' pedidos={pedidos5}/>
        </C.Container>
    )
}

export default Main
